operations.replace:
function normalizeThinking(
  thinking: AnthropicMessagesPayload["thinking"],
  maxTokens: number,
  effort?: "low" | "medium" | "high" | "max",
): Record<string, unknown> | undefined {
  if (effort === "low") {
    return { type: "disabled" }
  }
  if (!thinking && !effort) return undefined
  const type = thinking?.type ?? "enabled"
  let budgetTokens = thinking?.budget_tokens
  if (type === "adaptive" || type === "enabled") {
    switch (effort) {
      case "medium": { budgetTokens = budgetTokens ?? Math.max(1024, Math.floor(maxTokens * 0.5)); break }
      case "high": { budgetTokens = budgetTokens ?? Math.max(1024, Math.floor(maxTokens * 0.8)); break }
      case "max": { budgetTokens = Math.max(1024, maxTokens - 1); break }
      default: { budgetTokens = budgetTokens ?? Math.max(1024, maxTokens - 1) }
    }
    return { type: "enabled", budget_tokens: budgetTokens }
  }
  return thinking
}

// Sanitize stop_sequences: Copilot rejects whitespace-only entries (e.g. "\n" from Buddy)
if (body.stop_sequences) {
  const filtered = (body.stop_sequences as Array<string>).filter((s) => s.trim())
  if (filtered.length > 0) {
    body.stop_sequences = filtered
  } else {
    delete body.stop_sequences
  }
}

const effort = payload.output_config?.effort
const thinking = normalizeThinking(payload.thinking, payload.max_tokens, effort)
if (thinking) body.thinking = thinking
